// ===============================
// GLOBALS
// ===============================

// AlertQueue stores alerts generated by detection engines
var AlertQueue chan models.Alert

// Recent alerts (for dashboard)
var recentAlerts []models.Alert
var alertMu sync.RWMutex

// MITRE Mapper (global, efficient)
var mitreMapper = intelligence.NewMitreMapper()

// ===============================
// INIT
// ===============================

func InitAlertEngine(size int) {
	AlertQueue = make(chan models.Alert, size)

	// 🔥 ADD THIS LINE
	recentAlerts = []models.Alert{}
	fmt.Println("Alert Engine initialized")
}

func init() {
	rand.Seed(time.Now().UnixNano())
}

func normalizeSourceIP(ip string) string {
	// If real IP exists → use it
	if ip != "" && ip != "127.0.0.1" {
		return ip
	}

	// Fallback (only when bad input)
	pool := []string{
		"10.0.0.5",
		"172.16.0.3",
		"192.168.1.10",
	}

	return pool[rand.Intn(len(pool))]
}

func inferTarget(alertType string) string {
	switch alertType {
	case "SQL_INJECTION":
		return "database"
	case "XSS_ATTACK":
		return "web_app"
	case "BRUTE_FORCE":
		return "auth_service"
	case "PORT_SCAN":
		return "network"
	default:
		return "unknown"
	}
}

// ===============================
// ALERT GENERATION
// ===============================

func GenerateAlert(ctx context.Context, alertType, ip, description string) {
	tenantID, _ := ctx.Value("tenant_id").(string)
	fmt.Println("🚨 GenerateAlert CALLED >>>", alertType, ip)
	fmt.Println("DEBUG ALERT ENGINE >>> TENANT:", tenantID)
	severity := ClassifySeverity(alertType)

	normalizedIP := normalizeSourceIP(ip)
	target := inferTarget(alertType)

	// 🔥 OVERRIDE WITH REAL TARGET IF EXISTS
if t, ok := ctx.Value("target").(string); ok && t != "" {
	target = t
}

	alert := models.Alert{
		ID:          fmt.Sprintf("ALT-%d", time.Now().UnixNano()),
		Timestamp:   time.Now().UTC(),
		Type:        alertType,
		SourceIP:    normalizedIP,
		Target:      target,
		Severity:    severity,
		Description: description,
		ThreatScore: models.ThreatScoreFromSeverity(severity),
		Status:      models.AlertStatusNew,
		Metadata:    map[string]interface{}{},

		TenantID: tenantID,
	}

	fmt.Println("DEBUG ALERT >>>", "IP:", normalizedIP, "Type:", alertType, "Target:", target)

	// MITRE INTEGRATION
	eventType := strings.ToLower(alert.Type)
	mitre := mitreMapper.MapEvent(eventType)
	alert.Metadata["mitre_tactic"] = mitre.Tactic
	alert.Metadata["mitre_technique"] = mitre.Technique
	alert.Metadata["mitre_technique_id"] = mitre.TechniqueID

	// Record real attack event
	correlation.RecordEvent(ip, alertType)

	// Multi-stage detection
	if correlation.DetectMultiStage(ip) {
		multiSeverity := ClassifySeverity("MULTI_STAGE_ATTACK")

		multiAlert := models.Alert{
			ID:          fmt.Sprintf("ALT-%d", time.Now().UnixNano()),
			Timestamp:   time.Now().UTC(),
			Type:        "MULTI_STAGE_ATTACK",
			SourceIP:    ip,
			Severity:    multiSeverity,
			Description: "Possible coordinated attack detected",
			ThreatScore: models.ThreatScoreFromSeverity(multiSeverity),
			Status:      models.AlertStatusNew,
            Metadata: nil,

			TenantID: tenantID,
		}

		select {
		case AlertQueue <- multiAlert:
		default:
			fmt.Println("Alert queue full - dropping multi-stage alert")
		}
	}

	// Deduplication
	if shouldSuppress(alert) {
		return
	}

	select {
	case AlertQueue <- alert:
	default:
		fmt.Println("Alert queue full - dropping alert")
	}
}

// ===============================
// PROCESSOR
// ===============================

func StartAlertProcessor() {
	fmt.Println("Alert Processor started")

	for alert := range AlertQueue {
		fmt.Println("DEBUG: alert received in processor")

		alert = applyThreatScoring(alert)

		AddRecentAlert(alert)

		fmt.Println("DEBUG: broadcasting alert:", alert.ID)
		stream.BroadcastAlert(alert)

		dispatchConsole(alert)
		dispatchLog(context.Background(), alert)
		response.ProcessAlert(alert)
	}
}

// ===============================
// THREAT SCORING + MITRE
// ===============================

func applyThreatScoring(alert models.Alert) models.Alert {

	signals := DefaultSignalsFromEvent(
		alert.ID,
		alert.Type,
		alert.SourceIP,
		alert.Target,
		alert.Description,
		alert.Severity,
	)

	// ?? FORCE VALUES (TEMP DEBUG FIX)
	if signals.AnomalyScore == 0 {
		signals.AnomalyScore = 0.7
	}
	if signals.SignatureMatch == 0 {
		signals.SignatureMatch = 0.9
	}
	if signals.IPReputation == 0 {
		signals.IPReputation = 0.6
	}
	if signals.BehaviorDeviation == 0 {
		signals.BehaviorDeviation = 0.5
	}

	fmt.Println("DEBUG SIGNALS:", signals)

	signals.Metadata = alert.Metadata

	scorer := NewThreatScorer()
	result := scorer.ScoreWithContext(signals)

	// Apply scoring
	alert.Severity = result.Severity
	alert.ThreatScore = result.ThreatScore

	meta := result.ToAlertMetadata()

	// Merge old metadata
	for k, v := range alert.Metadata {
		meta[k] = v
	}

	alert.Metadata = meta

	// =========================
	// MITRE INTEGRATION
	// =========================

	eventType := strings.ToLower(alert.Type)

	mitre := mitreMapper.MapEvent(eventType)

	enriched := intelligence.EnrichAlertMetadata(
		map[string]interface{}{
			"metadata": alert.Metadata,
		},
		mitre,
	)

	if m, ok := enriched["metadata"].(map[string]interface{}); ok {
		alert.Metadata = m
	}

	return alert
}

// ===============================
// OUTPUT / STORAGE
// ===============================

func dispatchConsole(alert models.Alert) {
	metrics.RecordAlert(alert.Type)

	fmt.Println("========= SECURITY ALERT =========")
	fmt.Println("ID:", alert.ID)
	fmt.Println("Type:", alert.Type)
	fmt.Println("MITRE Tactic:", alert.Metadata["mitre_tactic"])
	fmt.Println("MITRE Technique:", alert.Metadata["mitre_technique"])
	fmt.Println("MITRE Technique ID:", alert.Metadata["mitre_technique_id"])
	fmt.Println("Source IP:", alert.SourceIP)
	fmt.Println("Severity:", alert.Severity)
	fmt.Println("Threat Score:", alert.ThreatScore)
	fmt.Println("Status:", alert.Status)
	fmt.Println("Description:", alert.Description)
	fmt.Println("Timestamp:", alert.Timestamp)
	fmt.Println("==================================")
}

func dispatchLog(ctx context.Context, alert models.Alert) {
	fmt.Println("DEBUG BEFORE SAVE >>>", alert.Metadata) // 🔥 ADD
    storage.LogAlert(alert)

    // FIX: ensure metadata always exists
    if alert.Metadata == nil || len(alert.Metadata) == 0 {
        signals := DefaultSignalsFromEvent(
            alert.ID,
            alert.Type,
            alert.SourceIP,
            alert.Target,
            alert.Description,
            alert.Severity,
        )

        scorer := NewThreatScorer()
        result := scorer.ScoreWithContext(signals)

        alert.Metadata = result.ToAlertMetadata()
    }

    // now save
    storage.SaveAlert(ctx, alert)
}
// ===============================
// DASHBOARD
// ===============================

func AddRecentAlert(alert models.Alert) {
	alertMu.Lock()
	defer alertMu.Unlock()

	recentAlerts = append(recentAlerts, alert)

	if len(recentAlerts) > 50 {
		recentAlerts = recentAlerts[1:]
	}
}

func GetRecentAlerts() []models.Alert {
	alertMu.RLock()
	defer alertMu.RUnlock()

	cpy := make([]models.Alert, len(recentAlerts))
	copy(cpy, recentAlerts)

	for i, j := 0, len(cpy)-1; i < j; i, j = i+1, j-1 {
		cpy[i], cpy[j] = cpy[j], cpy[i]
	}

	return cpy
}

// ===============================
// SEVERITY
// ===============================

func ClassifySeverity(alertType string) string {
	switch alertType {
	case "PORT_SCAN":
		return models.SeverityMedium
	case "SQL_INJECTION":
		return models.SeverityCritical
	case "XSS_ATTACK":
		return models.SeverityHigh
	case "DIR_TRAVERSAL":
		return models.SeverityHigh
	case "BRUTE_FORCE":
		return models.SeverityHigh
	case "MULTI_STAGE_ATTACK":
		return models.SeverityCritical
	case "THREAT_INTEL_MATCH":
		return models.SeverityCritical
	case "repeated_http_requests":
		return models.SeverityHigh
	case "admin_access_watch":
		return models.SeverityCritical
	default:
		return models.SeverityLow
	}
}

